<template>
  <div>
    <h1>{{ form.voteName }}</h1>
    <a-card style="width: 100%; margin: 20px 0; border-radius: 4px;" v-for="(item, index) in resultTypeSelect" :key="index" v-if="!loading" @click="item.disabled ? ()=> {} : route2Details(item.routeName)">
      <div style="display: flex; width: 100%;">
        <div style="flex: 1">
          <h2 :style="{ color : item.disabled ? '#ccc' : '' }">{{ item.title }}
            <a style="float: right; font-size: 28px"><a-icon type="right-circle" /></a>
          </h2>
        </div>
      </div>
    </a-card>
  </div>
</template>
<script>
import { voteBasicConfigurationDetail } from '@/api/voteBasicConfiguration'
export default {
  data() {
    return {
      loading: false,
      form: {},
      resultTypeSelect: [
        {
          title: '平均分（开发中）',
          routeName: '',
          disabled: true,
        },
        {
          title: '平均分-去除最高最低分',
          routeName: 'dataAnalysisAvgWithoutHLestScore',
          disabled: false,
        },
        {
          title: '总分（开发中）',
          routeName: '',
          disabled: true,
        },
        // {
        //   title: '平均分-自定义',
        //   routeName: 'dataAnalysisSelfDefine',
        //   disabled: false,
        // },
      ],
    }
  },
  mounted() {
    this.loadData()
  },
  methods: {
    loadData() {
      this.loading = true
      voteBasicConfigurationDetail({ id: this.$route.params.id }).then(res => {
        if (res) {
          this.form = res
        }
      }).finally(() => {
        this.loading = false
      })
    },
    openScreen() {
      window.open(`/#/dataDisplay/${this.$route.params.id}`, '_blank')
    },
    route2Details(routeName) {
      this.$router.push({
        name: routeName,
        voteId: this.$route.params.id,
        query: { rank: false },
      })
    },
  },
}
</script>
